let targetNumber = Math.floor(Math.random() * 100) + 1;
let attempts = 0;

const guessInput = document.getElementById('guess') as HTMLInputElement;
const submitBtn = document.getElementById('submit') as HTMLButtonElement;
const resetBtn = document.getElementById('reset') as HTMLButtonElement;
const messageDiv = document.getElementById('message') as HTMLDivElement;

function handleGuess() {
    const guess = parseInt(guessInput.value);

    if (isNaN(guess) || guess < 1 || guess > 100) {
        messageDiv.textContent = "Please enter a valid number between 1 and 100.";
        messageDiv.style.color = "red";
        return;
    }

    attempts++;

    if (guess === targetNumber) {
        messageDiv.textContent = `Correct! It took you ${attempts} attempts.`;
        messageDiv.style.color = "green";
        submitBtn.disabled = true;
        resetBtn.style.display = "inline-block";
    } else if (guess < targetNumber) {
        messageDiv.textContent = "Too low! Try again.";
        messageDiv.style.color = "orange";
    } else {
        messageDiv.textContent = "Too high! Try again.";
        messageDiv.style.color = "orange";
    }

    guessInput.value = "";
    guessInput.focus();
}

submitBtn.addEventListener('click', handleGuess);

guessInput.addEventListener('keypress', (e) => {
    if (e.key === 'Enter') {
        handleGuess();
    }
});

resetBtn.addEventListener('click', () => {
    targetNumber = Math.floor(Math.random() * 100) + 1;
    attempts = 0;
    messageDiv.textContent = "";
    submitBtn.disabled = false;
    resetBtn.style.display = "none";
    guessInput.focus();
});

import { serve } from "bun";

const server = serve({
  port: 3000,
  async fetch(req) {
    const url = new URL(req.url);

    // Serve the bundled JS
    if (url.pathname === "/game.js") {
      const build = await Bun.build({
        entrypoints: ["./src/game.ts"],
        minify: true,
      });
      return new Response(build.outputs[0]);
    }

    // Serve index.html
    if (url.pathname === "/" || url.pathname === "/index.html") {
      return new Response(Bun.file("./public/index.html"));
    }

    // Default: 404
    return new Response("Not Found", { status: 404 });
  },
});

console.log(`Server running at http://localhost:${server.port}`);
